12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061import pandas as pdimport numpy as npd = &#123;&apos;one&apos; : pd.Series([1., 2., 3.], index=[&apos;a&apos;, &apos;b&apos;, &apos;c&apos;]),&apos;two&apos; : pd.Series([1., 2., 3., 4.], index=[&apos;a&apos;, &apos;b&apos;, &apos;c&apos;, &apos;d&apos;])&#125;df=pd.DataFrame(d)print dfmean=df.mean()print mean#可以通过传递一个list对象来创建一个Series，pandas会默认创建整型索引：#通过传递一个numpy array，时间索引以及列标签来创建一个DataFrame：dates=pd.date_range(&apos;20161120&apos;,periods=6)print datesdf1=pd.DataFrame(np.random.randn(6,4),index=dates,columns=list(&apos;ABCD&apos;))print df1#通过传递一个能够被转换成类似序列结构的字典对象来创建一个DataFrame：df2=pd.DataFrame(&#123;&apos;A&apos;:1.,&apos;B&apos;:pd.Series(1,index=list(range(5)),dtype=&apos;float32&apos;),&apos;C&apos;:pd.Timestamp(&apos;20161124&apos;),&apos;D&apos;:np.array([3]*5,dtype=&apos;int32&apos;),&apos;E&apos;:pd.Categorical([&apos;test&apos;,&apos;train&apos;,&apos;test&apos;,&apos;train&apos;,&apos;test&apos;]),&apos;F&apos;:&apos;foo&apos;&#125;)print df2# 查看frame中头部和尾部的行：print df1.tail(1)print df1.head(3)# 显示索引、列和底层的numpy数据：print df2.indexprint df2.columnsprint df2.values# describe()函数对于数据的快速统计汇总：print df1.describe()# 对数据的转置：print df1.T# 按轴进行排序print df1.sort_index(axis=1,ascending=False)# 按值进行排序print df1.sort(columns=&apos;B&apos;)# 选择一个单独的列，这将会返回一个Series，等同于df.A：print &apos;df1[A]&apos;+&apos;
&apos;,df1[&apos;A&apos;]# 通过[]进行选择，这将会对行进行切片print &apos;df1[0:3]&apos;+&apos;
&apos;,df1[0:2],&apos;
&apos;# 使用标签来获取一个交叉的区域print df1.loc[dates[0]],&apos;

&apos;# 通过标签来在多个轴上进行选择print df1.loc[dates[0:2],[&apos;C&apos;,&apos;A&apos;]]# pandas使用浮点值NaN（Not a Number）表示浮点和非浮点数组中的缺失数据。 # NA处理办法 dropna 根据各标签值中是否存在缺失数据对轴标签进行过滤，可通过阀值调节对缺失值的容忍度 fillna 用指定的或插值方法(如ffil或bfill)填充缺失数据 isnull 返回一个含有布尔值的对象，这些布尔值表示哪些值是缺失值/NA，该对象的类型与源类型一样 notnull isnull的否定式
